tool_calls:
awk '
BEGIN { FS=","; ORS=""; print "[\n" }
NR==1 {
  # Store header fields
  for (i=1; i<=NF; i++) headers[i] = $i
  ncols = NF
  next
}
{
  if (NR > 2) print ",\n"   # comma separator between objects
  print "  {"
  for (i=1; i<=ncols; i++) {
    printf "\"%s\": \"%s\"", headers[i], $i
    if (i < ncols) printf ", "
  }
  print "}"
}
END { print "\n]\n" }
' /data/users.csv

